#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long n, m;
        scanf("%lld %lld", &n, &m);
        long long ans = 2 % m;
        printf("%lld\n", ans);
    }
    return 0;
}

